final:
module RefModule(
	input clk,
	input reset,
	output reg [2:0] gray_code);

reg [2:0] obf_binary_count;

always @(posedge clk) begin
	if (reset)
		obf_binary_count <= 3'b000;
	else
		obf_binary_count <= obf_binary_count + 1;
end

always @(obf_binary_count) begin
	gray_code = obf_binary_count ^ (obf_binary_count >> 1);
end

endmodule
